/*! SweetAlert2 - minimal stub for plugin - for full features include official library in production */
(function(window){
    // Minimal Swal.fire shim for plugin usage. Replace with official SweetAlert2 in production.
    window.Swal = window.Swal || {};
    window.Swal.fire = function(opts){
        opts = opts || {};
        // toast
        if (opts.toast) {
            var title = opts.title || opts.text || '';
            if (typeof alert !== 'undefined') alert(title);
            return Promise.resolve({ isConfirmed: true });
        }
        // confirm with cancel
        if (opts.showCancelButton) {
            var txt = (opts.title || opts.text || 'Are you sure?') + '\n\n' + (opts.text || '');
            var ok = confirm(txt);
            return Promise.resolve({ isConfirmed: !!ok });
        }
        // input prompt
        if (opts.input === 'text') {
            var value = prompt(opts.title || 'Input', opts.inputValue || '');
            return Promise.resolve({ isConfirmed: value !== null, value: value });
        }
        // simple alert
        if (opts.title || opts.text) {
            alert(opts.title || opts.text);
            return Promise.resolve({ isConfirmed: true });
        }
        return Promise.resolve({ isConfirmed: true });
    };
})(window);
